def dequeue(self):
    cursor = self.conn.execute(
        'UPDATE tasks SET status = "processing" '
        'WHERE id = (SELECT id FROM tasks WHERE status = "pending" LIMIT 1) '
        'RETURNING id, payload'
    )
    row = cursor.fetchone()
    self.conn.commit()
    if row:
        return Task(row[0], row[1])
    return None

def complete(self, task_id: str):
    self.conn.execute('UPDATE tasks SET status = "completed" WHERE id = ?', (task_id,))
    self.conn.commit()

def fail(self, task_id: str):
    self.conn.execute('UPDATE tasks SET status = "failed" WHERE id = ?', (task_id,))
    self.conn.commit()

def process(self, task: Task):
    try:
        task.execute()
        self.queue.complete(task.id)
    except Exception as e:
        self.queue.fail(task.id)
        raise
